  ('elementary-7fec267e-moex-00444', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '下列文句「」內的詞語，用法錯誤的選項是：', '["他「逢人說項」，到處吹噓自己的勇猛", "他向來循規蹈矩，不會做出「雞鳴狗盜」的勾當", "經過此番激烈的砲戰，從此敵人不敢再「越雷池一步」", "李安拍了很多好片，獲獎無數，是導演行業的「個中翹楚」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00445', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用錯誤？', '["警方接到報案趕到現場，匪徒早已「杳如黃鶴」，不見蹤影", "這項工程最終靠著大家「任勞任怨」、努力不懈，才得以完成", "王教授的演講十分精彩，全場人士聽得「津津有味」，讚嘆不已", "我們公司非常嚴格，對任何流程的監控都小心翼翼，「瑕不掩瑜」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00446', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '下列選項，何者最適宜「醫界」使用？', '["功著杏林", "利惠人群", "大業千秋", "福國利民"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00447', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '下列選項中的題辭與使用場合搭配，何者正確？', '["畢業：學無止境", "女喪：孟母遺風", "退休：德業長昭", "遷居：名山事業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00448', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用正確？', '["人事變化無常，不禁令人生起「樹猶如此」的慨嘆", "時逢春季，陽明山處處「蕙質蘭心」，吸引民眾駐足", "彎月高懸天際，「送眼流眉」的姿態，美得令人屏息", "跨年人潮眾多，一時之間「擢髮難數」，捷運只好加開班次"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00449', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '「後人認為司馬遷在《史記》裡對現實政治『微文刺譏』，因而視《史記》為『謗書』。當 然，司馬遷在寫作過程中，將其個人際遇的鬱結，融於書中，是非常可能的。至於『微文刺 譏』，誹謗今上，在現實的政治環境下，卻是不可能的。身受現實政治摧殘的司馬遷，如何 超越桎梏，在不觸犯時諱的情況下，記錄當代歷史，頗費思量。」 根據上文，下列選項何者最符合文意？', '["司馬遷受現實政治摧殘，因而在《史記》誹謗今上", "《史記》「微文刺譏」展現歷史學家的真誠與勇氣", "如何寄託個人的鬱結，是司馬遷撰作《史記》時最費思量者", "能忠實呈現當代歷史而不觸犯時諱，是《史記》寫作的難處"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00450', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '「根據影片中象龜熟練的獵捕技巧，生態學家Justin Gerlach 推測或許這些象龜其實早已學 會捕獵，但因為過去人類侵入牠們的棲息地，大量獵捕各種生物，而大大影響原棲息地的食 物鏈，才導致象龜改變原本的習性。或許也是弗雷格特島所提倡的保育計畫實行得很成功， 使象龜們回歸了原始的生長環境，因此象龜們的狩獵本性就露出來了。」 根據上文，下列選項何者符合文意？', '["過去人們普遍認為象龜不會獵捕", "象龜獵捕行為是被人類所逼迫的", "象龜改變原本的習性後開始吃肉", "只有弗雷格特島的象龜才會獵捕"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00451', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '「臺灣物產的文獻紀錄，可考者最早可溯至 1607 年陳第的《東番記》，食用作物玉米、番 薯原產於美洲，據推測是從西班牙的殖民地菲律賓引入，再輾轉進入臺灣。也提到當時原住 民所種的甘蔗，可見甘蔗引進臺灣的時間很久遠，應是引自中國。檳榔等作物可能直接引自 中南半島。臺灣在納入了全球化的經濟貿易後，連帶的進入生態交流網絡之中。」 根據上文，下列選項正確的是：', '["臺灣並無原生食用植物，都是殖民者由島外引進栽種", "甘蔗很早就引進臺灣，顯見臺灣的製糖工業源遠流長", "全球交通、跨國貿易、殖民等因素，影響了飲食物產", "從物產判斷，中、菲、美洲是臺灣當時三大貿易夥伴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00452', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '一位醫師作家以當代的醫學角度思考詩仙李白為何如此愛喝酒而寫道：「李白聚會喝酒寫出 來的詩，統稱為『宴飲詩』，趁難得的美好時節與朋友相聚，在有限的年華暢飲，李白因此 寫下了 的千古名句。在詩中，他大力稱述飲酒的妙處，高聲讚揚及時行樂。這或許是 因為李白的腦部受到酒精影響，瀰漫著舒服愉悅的感覺。」 根據上文， 中最適合填入的詩句是：', '["舉頭望明月，低頭思故鄉", "蘭陵美酒鬱金香，玉碗盛來琥珀光", "人生得意須盡歡，莫使金樽空對月", "花間一壺酒，獨酌無相親，舉杯邀明月，對影成三人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00453', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-34c7f7f6', 'sub-elementary-7fec267e-02', NULL, 'single_choice', '「你不會因為有了小孩就更有父母的樣子，就像擁有一架鋼琴不會讓你變成鋼琴家。」下列 選項，何者最符合文意？', '["只要開始，就有機會", "動機是最單純的力量", "有力的理由造成有力的行動", "付諸行動，從做中學累積成果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
